WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/14.0/connection.js")} 
{!REQUIRESCRIPT("/soap/ajax/14.0/apex.js")} 

var valid = true;
var confirmed = false;
var message = 'The following fields must be filled out before you can certify the purchase: \n\n';

if ( {!ISBLANK( HOMEtracker__Service_File__c.HOMEtracker__Applicant__c )} ) {
    valid = false;
    message += '* Applicant\n';
}

if ( {!ISBLANK(  HOMEtracker__Service_File__c.HOMEtracker__Property__c  )} ) {
    valid = false;
    message += '* Property\n';
}

if ( {!ISBLANK(  HOMEtracker__Service_File__c.HOMEtracker__Purchase_Price__c  )} ) {
    valid = false;
    message += '* Purchase Price\n';
}

if ( {!ISBLANK(  HOMEtracker__Service_File__c.HOMEtracker__Close_Date__c  )} ) {
    valid = false;
    message += '* Close Date\n';
}

var confirmationMessage = "Certify the purchase only after you have entered and verified all purchase transaction and homebuyer information.\n\nWhen you certify the purchase, the following fields will be updated:\n- Purchase Certification Date is set to Today’s date \n- Subsidy Beyond Market Value and Close Date are copied into Certified versions of those fields \n- Number of Children at Purchase and Number of Seniors At Purchase are populated based on household members’ Birthdates and the Service File Close Date \n \n\nBefore proceeding, remember to: \n *Copy the Property address to Applicant and Co-Applicant Contact records. Use the Purchase Summary or Copy Address to Contacts link. \n *Update statuses to reflect ownership. Use the Purchase Summary or Update Status button to update statuses on the Property, Applicant Contact and Service File.\n\nAre you ready to Certify the Purchase?";

if (valid) {
// confirm
confirmed = window.confirm(confirmationMessage); 
} else {
// show error message
alert(message);
}

if (confirmed) {
// run the webservice 
var serviceFileID = sforce.apex.execute("HOMEtracker.ServiceFileWebServices","certifyPurchase", {serviceFileID: "{!CASESAFEID(HOMEtracker__Service_File__c.Id)}"}); 

// redirect to the new task 
top.location.replace("/" + serviceFileID);
}
